421	// buildSparkline returns a 24-element slice of hourly token totals for the
422	// last 24 hours (oldest-first). Returns nil when fewer than 6 of the 24
423	// hourly buckets have non-zero token counts — the UI uses that floor to
424	// suppress noisy single-spike sparklines (FEAT-014 AC 2: "Sparkline renders
425	// when ≥6 hourly buckets of usage are available").
426	func buildSparkline(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) []int {
427		if len(entries) == 0 {
428			return nil
429		}
430		buckets := agent.BucketUsage(entries, name, kind, now, 1, time.Hour)
431		totals := make([]int, len(buckets))
432		nonEmpty := 0
433		for i, b := range buckets {
434			totals[i] = b.Tokens
435			if b.Tokens > 0 {
436				nonEmpty++
437			}
438		}
439		if nonEmpty < 6 {
440			return nil
441		}
442		return totals
443	}
